/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lançamento Pedidos"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedStsDsp.IsEmpty() &FilterPedStsDspValueDescription = &PedStsDsp.EnumerationDescription()
print printBlockFilterPedStsDsp EndIf If not &PedTraSaiCod.IsEmpty() print printBlockFilterPedTraSaiCod EndIf If not &PedTraSaiRaz.IsEmpty() print printBlockFilterPedTraSaiRaz EndIf If not &PedDtaFat.IsEmpty() print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To.IsEmpty() &PedDtaFat_To_Description = format('%1 (%2)', "Faturado", "até") print printBlockFilterPedDtaFat_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAEMS' &PedDtaEms1.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms1.IsEmpty() &FilterPedDtaEmsDescription = "Emissão" &PedDtaEms = &PedDtaEms1 print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To1.IsEmpty() &FilterPedDtaEmsDescription = format('%1 (%2)', "Emissão", "até") &PedDtaEms = &PedDtaEms_To1 print printBlockFilterPedDtaEms EndIf Case &DynamicFiltersSelector1 = !'PEDDTADSP' &PedDtaDsp1.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp1.IsEmpty() &FilterPedDtaDspDescription = "Despachado" &PedDtaDsp = &PedDtaDsp1 print printBlockFilterPedDtaDsp EndIf If not &PedDtaDsp_To1.IsEmpty() &FilterPedDtaDspDescription = format('%1 (%2)', "Despachado", "até") &PedDtaDsp = &PedDtaDsp_To1 print printBlockFilterPedDtaDsp EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAEMS' &PedDtaEms2.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms2.IsEmpty() &FilterPedDtaEmsDescription = "Emissão" &PedDtaEms = &PedDtaEms2 print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To2.IsEmpty() &FilterPedDtaEmsDescription = format('%1 (%2)', "Emissão", "até") &PedDtaEms = &PedDtaEms_To2 print printBlockFilterPedDtaEms EndIf Case &DynamicFiltersSelector2 = !'PEDDTADSP' &PedDtaDsp2.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp2.IsEmpty() &FilterPedDtaDspDescription = "Despachado" &PedDtaDsp = &PedDtaDsp2 print printBlockFilterPedDtaDsp EndIf If not &PedDtaDsp_To2.IsEmpty() &FilterPedDtaDspDescription = format('%1 (%2)', "Despachado", "até") &PedDtaDsp = &PedDtaDsp_To2 print printBlockFilterPedDtaDsp EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAEMS' &PedDtaEms3.FromString(&GridStateDynamicFilter.Value) &PedDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEms3.IsEmpty() &FilterPedDtaEmsDescription = "Emissão" &PedDtaEms = &PedDtaEms3 print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To3.IsEmpty() &FilterPedDtaEmsDescription = format('%1 (%2)', "Emissão", "até") &PedDtaEms = &PedDtaEms_To3 print printBlockFilterPedDtaEms EndIf Case &DynamicFiltersSelector3 = !'PEDDTADSP' &PedDtaDsp3.FromString(&GridStateDynamicFilter.Value) &PedDtaDsp_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaDsp3.IsEmpty() &FilterPedDtaDspDescription = "Despachado" &PedDtaDsp = &PedDtaDsp3 print printBlockFilterPedDtaDsp EndIf If not &PedDtaDsp_To3.IsEmpty() &FilterPedDtaDspDescription = format('%1 (%2)', "Despachado", "até") &PedDtaDsp = &PedDtaDsp_To3 print printBlockFilterPedDtaDsp EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order PedDtaFat when &OrderedBy = 3 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 3 AND &OrderedDsc = True
using DSWWPedidoVendaDespacho(&PedCod, &PedSts, &PedCliCod, &PedStsDsp, &PedTraSaiCod, &PedTraSaiRaz , &PedDtaFat, &PedDtaFat_To, &LctTip, &LctAtuSal, &PedBlq, &FilCod , &DynamicFiltersSelector1, &LctCod1, &PedVenCod1, &PedDtaEms1, &PedDtaEms_To1, &PedDtaDsp1 , &PedDtaDsp_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &LctCod2, &PedVenCod2, &PedDtaEms2 , &PedDtaEms_To2, &PedDtaDsp2, &PedDtaDsp_To2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3 , &PedVenCod3, &PedDtaEms3, &PedDtaEms_To3, &PedDtaDsp3, &PedDtaDsp_To3) &gridPedCliCodRaz = iif(PedCliCodRaz.Length() > 30, Substr(PedCliCodRaz,1,30)+'...', PedCliCodRaz)
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWPedidoVendaDespachoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWPedidoVendaDespachoGridState")) Else &GridState.FromXml(&Session.Get(!"WWPedidoVendaDespachoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSDSP" &PedStsDsp.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAICOD" &PedTraSaiCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAIRAZ" &PedTraSaiRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAFAT" &PedDtaFat.FromString(&GridStateFilterValue.Value) &PedDtaFat_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
